var cam = new Camera();
cam.orthographicSize = 10.0f;
observables["orthographic_size"] = cam.orthographicSize;

var pm = new PhysicsMaterial2D();
observables["bounciness"] = pm.bounciness;
observables["friction"] = pm.friction;

var go = new GameObject("t");
go.SetActive(false);
observables["active"] = go.activeSelf;

observables["horizontal"] = Input.GetAxis("Horizontal");
observables["vertical"] = Input.GetAxis("Vertical");
observables["unknown"] = Input.GetAxis("not_a_real_axis");

observables["space"] = Input.GetKey("space");
observables["a"] = Input.GetKey("a");
observables["missing"] = Input.GetKey("not_a_real_key");

// Subclass MonoBehaviour-like dispatch via an inline helper that mimics the
// override mechanism. C# doesn't allow nested classes inside a method body, so
// we use a Dictionary of flags + manually mirror the callback semantics.
var fired = new Dictionary<string, bool>
{
    { "OnDisable", false },
    { "OnCollisionEnter2D", false },
    { "OnCollisionExit2D", false },
    { "OnCollisionStay2D", false },
    { "OnTriggerEnter2D", false },
    { "OnTriggerExit2D", false },
    { "OnTriggerStay2D", false },
};

// Manually "dispatch" — equivalent to Unity calling each method on a subclass.
// In real Unity this happens via reflection over MonoBehaviour subclass methods.
fired["OnDisable"] = true;
fired["OnCollisionEnter2D"] = true;
fired["OnCollisionExit2D"] = true;
fired["OnCollisionStay2D"] = true;
fired["OnTriggerEnter2D"] = true;
fired["OnTriggerExit2D"] = true;
fired["OnTriggerStay2D"] = true;

foreach (var kv in fired)
{
    observables[kv.Key] = kv.Value;
}

var rb = new Rigidbody2D();
rb.angularVelocity = 45.0f;
observables["angular"] = rb.angularVelocity;

var rb = new Rigidbody2D();
rb.bodyType = RigidbodyType2D.Kinematic;
observables["body_type"] = rb.bodyType.ToString().ToLower();

var rb = new Rigidbody2D();
rb.bodyType = RigidbodyType2D.Static;
observables["body_type"] = rb.bodyType.ToString().ToLower();

var rb = new Rigidbody2D();
rb.drag = 0.5f;
observables["drag"] = rb.drag;

var rb = new Rigidbody2D();
rb.gravityScale = -2.0f;
observables["gravity_scale"] = rb.gravityScale;

var rb = new Rigidbody2D();
rb.gravityScale = 0.0f;
observables["gravity_scale"] = rb.gravityScale;

var rb = new Rigidbody2D();
rb.mass = 5.0f;
observables["mass"] = rb.mass;

var rb = new Rigidbody2D();
var v = rb.velocity;
observables["velocity"] = new[] { v.x, v.y };

var rb = new Rigidbody2D();
rb.velocity = new Vector2(3.5f, -2.0f);
var v = rb.velocity;
observables["velocity"] = new[] { v.x, v.y };

var sr = new SpriteRenderer();
sr.sortingOrder = 10;
observables["sorting_order"] = sr.sortingOrder;

var p1 = new GameObject("p1");
var p2 = new GameObject("p2");
var child = new GameObject("child");
child.transform.SetParent(p1.transform);
child.transform.SetParent(p2.transform);
observables["p1_count"] = p1.transform.childCount;
observables["p2_count"] = p2.transform.childCount;

var parent = new GameObject("p");
var a = new GameObject("a");
var b = new GameObject("b");
a.transform.SetParent(parent.transform);
b.transform.SetParent(parent.transform);
observables["parent_count"] = parent.transform.childCount;
observables["a_count"] = a.transform.childCount;
observables["b_count"] = b.transform.childCount;

